const fs = require('fs');
const path = require('path');

const baseDir = '/Users/anhd/Documents/wordpress/demo-pdn/app/public/wp-content/themes/lacadev-client-child/block-gutenberg';

const blocks = fs.readdirSync(baseDir).filter(f => fs.statSync(path.join(baseDir, f)).isDirectory());

blocks.forEach(block => {
    const editJsPath = path.join(baseDir, block, 'edit.js');
    if (!fs.existsSync(editJsPath)) return;

    let editJs = fs.readFileSync(editJsPath, 'utf8');
    
    let modified = false;

    // Check for syntax error pattern generated by previous script
    // It looks like: import {\n    ToggleControl,\n    RangeControl,\n, ColorPicker, RangeControl } from '@wordpress/components';
    const componentImportRegex = /import\s*\{([^}]*)\}\s*from\s*'@wordpress\/components';/g;

    editJs = editJs.replace(componentImportRegex, (match, inner) => {
        const tokens = inner.split(',').map(s => s.trim()).filter(Boolean);
        const uniqueTokens = Array.from(new Set(tokens));
        modified = true;
        return `import {\n    ${uniqueTokens.join(',\n    ')}\n} from '@wordpress/components';`;
    });

    if (modified) {
        fs.writeFileSync(editJsPath, editJs);
        console.log(`Fixed imports for ${block}`);
    }
});
